import{_ as e,o as t,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Warp — AI-Native Terminal with Integrated Coding Agent","description":"","frontmatter":{"title":"Warp — AI-Native Terminal with Integrated Coding Agent","status":"complete"},"headers":[],"relativePath":"research/agents/warp/index.md","filePath":"research/agents/warp/index.md"}'),r={name:"research/agents/warp/index.md"};function i(l,a,o,p,d,c){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="warp" tabindex="-1">Warp <a class="header-anchor" href="#warp" aria-label="Permalink to &quot;Warp&quot;">​</a></h1><blockquote><p>The terminal reimagined from scratch in Rust: a GPU-accelerated, block-based terminal emulator with a deeply integrated AI agent platform (&quot;Oz&quot;) that can attach to live interactive processes, execute in the cloud, and unify local and remote agent workflows.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Warp</strong> is an AI-native terminal application built entirely in <strong>Rust</strong> with <strong>Metal</strong> GPU rendering. Unlike every other AI coding agent — which wraps an existing terminal (Claude Code, Codex CLI, aider) — Warp <strong>is</strong> the terminal itself. This architectural distinction is fundamental: because Warp controls the entire rendering pipeline, PTY management, and input handling, its agent has capabilities no wrapper-based agent can match.</p><p>Founded by <strong>Zach Lloyd</strong> (former Google Docs engineering lead), Warp launched publicly in 2022 as a modern terminal replacement and has since evolved into a full agent platform. The company has raised $170M+ in funding, reflecting the scale of ambition: replace the 50-year-old terminal paradigm with something AI-first.</p><h3 id="what-makes-warp-special" tabindex="-1">What Makes Warp Special <a class="header-anchor" href="#what-makes-warp-special" aria-label="Permalink to &quot;What Makes Warp Special&quot;">​</a></h3><ol><li><p><strong>Terminal IS the Agent Environment</strong>: Warp&#39;s agent doesn&#39;t shell out — it reads the live terminal buffer, writes to the PTY, and can attach to interactive processes (psql, vim, python REPL, gdb). No other coding agent can &quot;see&quot; a running <code>npm run dev</code> server&#39;s output and interact with it in real time.</p></li><li><p><strong>GPU-Accelerated Rendering</strong>: Custom Rust → Metal pipeline achieving 400+ fps with ~1.9ms average redraw time. ~250 lines of Metal shader code render three primitive types (rects, images, glyphs). This isn&#39;t cosmetic — it enables the rich block-based UI that makes agent interaction feel native.</p></li><li><p><strong>Block-Based Data Model</strong>: Every command+output pair is a discrete &quot;block&quot; with its own grid (forked from Alacritty&#39;s grid model). Blocks can be individually selected, shared, referenced by the agent, and composed into context. This replaces the traditional terminal&#39;s single scrollback buffer.</p></li><li><p><strong>Oz Agent Platform</strong>: Unifies local agents (running in the Warp app) and cloud agents (running on Warp infrastructure or self-hosted) under a single orchestration platform. Cloud agents can be triggered by Slack, Linear, GitHub events, webhooks, or schedules.</p></li><li><p><strong>Agent Modality</strong>: Two distinct interaction modes — a clean terminal for command execution and a dedicated conversation view for multi-turn agent workflows. The agent can seamlessly transition between executing commands and conversational planning.</p></li><li><p><strong>Full Terminal Use</strong>: The agent can start interactive tools, read their output from the terminal buffer, write input to them, and hand control back to the human. This &quot;takeover/handback&quot; pattern is unique to terminal-native agents.</p></li><li><p><strong>Skills &amp; Rules System</strong>: Reusable markdown instruction sets (SKILL.md files) with parameter support, plus hierarchical project rules via AGENTS.md files — giving teams fine-grained control over agent behavior per directory.</p></li></ol><h3 id="key-stats" tabindex="-1">Key Stats <a class="header-anchor" href="#key-stats" aria-label="Permalink to &quot;Key Stats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td><strong>Language</strong></td><td>Rust (client), with Metal shaders (macOS)</td></tr><tr><td><strong>Rendering</strong></td><td>400+ fps, ~1.9ms avg redraw, Metal GPU</td></tr><tr><td><strong>Open Source</strong></td><td>No (issues-only GitHub repo; plans to open-source UI framework)</td></tr><tr><td><strong>Platform</strong></td><td>macOS (primary), Linux, Windows (coming)</td></tr><tr><td><strong>Models</strong></td><td>GPT-5.x, Claude Opus/Sonnet 4.x, Gemini 3 Pro, Gemini 2.5 Pro</td></tr><tr><td><strong>Auto Modes</strong></td><td>Cost-efficient, Responsive, Genius</td></tr><tr><td><strong>Terminal-Bench 2.0</strong></td><td>Rank #31 (61.2%), #36 (59.1%), #52 (50.1%)</td></tr><tr><td><strong>Terminal-Bench 1.0</strong></td><td>Rank #11 (52.0%)</td></tr><tr><td><strong>Funding</strong></td><td>$170M+ raised</td></tr><tr><td><strong>SOC 2</strong></td><td>Compliant; Zero Data Retention with all LLM providers</td></tr></tbody></table><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        Warp Terminal App                          │</span></span>
<span class="line"><span>│                     (Rust + Metal GPU Rendering)                  │</span></span>
<span class="line"><span>│                                                                   │</span></span>
<span class="line"><span>│  ┌──────────────┐  ┌──────────────┐  ┌─────────────────────────┐ │</span></span>
<span class="line"><span>│  │   Terminal    │  │    Agent     │  │     Oz Orchestration    │ │</span></span>
<span class="line"><span>│  │    View       │  │ Conversation │  │       Platform          │ │</span></span>
<span class="line"><span>│  │              │  │    View      │  │                         │ │</span></span>
<span class="line"><span>│  │  ┌────────┐  │  │  Multi-turn  │  │  ┌───────┐ ┌────────┐  │ │</span></span>
<span class="line"><span>│  │  │ Block  │  │  │  planning &amp;  │  │  │ Local │ │ Cloud  │  │ │</span></span>
<span class="line"><span>│  │  │ Block  │  │  │  execution   │  │  │ Agent │ │ Agents │  │ │</span></span>
<span class="line"><span>│  │  │ Block  │  │  │              │  │  │       │ │        │  │ │</span></span>
<span class="line"><span>│  │  └────────┘  │  └──────┬───────┘  │  └───┬───┘ └───┬────┘  │ │</span></span>
<span class="line"><span>│  └──────┬───────┘         │          │      │         │        │ │</span></span>
<span class="line"><span>│         │                 │          └──────┼─────────┼────────┘ │</span></span>
<span class="line"><span>│         ▼                 ▼                 ▼         ▼          │</span></span>
<span class="line"><span>│  ┌─────────────────────────────────────────────────────────────┐ │</span></span>
<span class="line"><span>│  │                    PTY / Shell Hooks                         │ │</span></span>
<span class="line"><span>│  │         (precmd/preexec → Block boundaries)                 │ │</span></span>
<span class="line"><span>│  │    ┌──────────┐  ┌──────────┐  ┌──────────────────┐        │ │</span></span>
<span class="line"><span>│  │    │ Grid per │  │ Grid per │  │ Grid per block   │        │ │</span></span>
<span class="line"><span>│  │    │ block    │  │ block    │  │ (Alacritty fork)  │        │ │</span></span>
<span class="line"><span>│  │    └──────────┘  └──────────┘  └──────────────────┘        │ │</span></span>
<span class="line"><span>│  └─────────────────────────────────────────────────────────────┘ │</span></span>
<span class="line"><span>│                                                                   │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │              Rust → Element Tree → GPU Primitives           │  │</span></span>
<span class="line"><span>│  │         (rect, image, glyph) → Metal Shaders (~250 LOC)    │  │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>         │                                          │</span></span>
<span class="line"><span>         ▼                                          ▼</span></span>
<span class="line"><span>┌──────────────────┐                    ┌──────────────────────┐</span></span>
<span class="line"><span>│   Codebase       │                    │   Cloud / Triggers   │</span></span>
<span class="line"><span>│   Context        │                    │                      │</span></span>
<span class="line"><span>│  (Semantic Index, │                    │  Slack, Linear,      │</span></span>
<span class="line"><span>│   Embeddings)    │                    │  GitHub, Webhooks,   │</span></span>
<span class="line"><span>│                  │                    │  Schedules           │</span></span>
<span class="line"><span>└──────────────────┘                    └──────────────────────┘</span></span></code></pre></div><h2 id="comparison-with-wrapper-based-agents" tabindex="-1">Comparison with Wrapper-Based Agents <a class="header-anchor" href="#comparison-with-wrapper-based-agents" aria-label="Permalink to &quot;Comparison with Wrapper-Based Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Warp (Terminal-Native)</th><th>Wrapper Agents (Claude Code, etc.)</th></tr></thead><tbody><tr><td>Terminal control</td><td>Full PTY ownership</td><td>Spawns subprocesses</td></tr><tr><td>Interactive apps</td><td>Attach, read buffer, write input</td><td>Cannot interact with running apps</td></tr><tr><td>Rendering</td><td>Custom GPU pipeline</td><td>Inherits host terminal</td></tr><tr><td>Command context</td><td>Block-level isolation</td><td>Raw text parsing</td></tr><tr><td>Output awareness</td><td>Reads live terminal buffer</td><td>Captures stdout/stderr</td></tr><tr><td>Cloud execution</td><td>Native cloud agent support</td><td>Separate infrastructure needed</td></tr></tbody></table><h2 id="files-in-this-research" tabindex="-1">Files in This Research <a class="header-anchor" href="#files-in-this-research" aria-label="Permalink to &quot;Files in This Research&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Contents</th></tr></thead><tbody><tr><td><a href="./architecture.html">architecture.md</a></td><td>Rust+Metal GPU rendering, PTY/block system, data model, UI framework, Oz platform</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>Oz agent request processing, Full Terminal Use, permissions, planning, takeover/handback</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>File ops, shell execution, web search, MCP, Computer Use, LSP, code review, voice</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>Semantic indexing, multi-modal context, Rules, Skills, Warp Drive, forking/compaction</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Terminal-native patterns, GPU pipeline, block model, Full Terminal Use, cloud+local unification</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Terminal-Bench 2.0 and 1.0 results, model configurations, performance analysis</td></tr><tr><td><a href="./references.html">references.md</a></td><td>Comprehensive URL reference: docs, blog posts, GitHub, benchmarks</td></tr></tbody></table>`,15)])])}const u=e(r,[["render",i]]);export{m as __pageData,u as default};
